JWT_SECRET = "your-secret-key-here"
JWT_ALGORITHM = "HS256"
ALLOWED_ADMIN_METHODS = [
    "/your_service.YourService/AdminMethod",
    "/your_service.YourService/OperationalMethod"
]
EXEMPTED_PATHS = [
    "/health",
    "/metrics",
    "/admin/*"
]

class AuthInterceptor(ServerInterceptor):
    def __init__(self):
        self.logger = logging.getLogger(__name__)

    def intercept(self, method, request, context, method_handler):
        try:
            # Check if method is exempted
            method_full_name = method_handler.method
            if self._is_exempted(method_full_name):
                return method(request, context)
            
            # Check if method is admin and should bypass auth
            if self._is_admin_method(method_full_name):
                return method(request, context)
            
            # Extract and validate token
            auth_header = dict(context.invocation_metadata()).get('authorization')
            if not auth_header:
                self.logger.warning("No authorization header found")
                context.abort(StatusCode.UNAUTHENTICATED, "Missing authorization header")
                return
            
            if not auth_header.startswith("Bearer "):
                self.logger.warning("Invalid authorization header format")
                context.abort(StatusCode.UNAUTHENTICATED, "Invalid authorization header")
                return
            
            token = auth_header.split(" ")[1]
            payload = jwt.decode(token, JWT_SECRET, algorithms=[JWT_ALGORITHM])
            
            # Add user info to context for downstream use
            context.user_info = payload
            
            # Proceed with method execution
            return method(request, context)
            
        except jwt.ExpiredSignatureError:
            self.logger.warning("Token expired")
            context.abort(StatusCode.UNAUTHENTICATED, "Token expired")
            return
        except jwt.InvalidTokenError:
            self.logger.warning("Invalid token")
            context.abort(StatusCode.UNAUTHENTICATED, "Invalid token")
            return
        except Exception as e:
            self.logger.error(f"Authentication error: {str(e)}")
            context.abort(StatusCode.UNAUTHENTICATED, "Authentication failed")
            return

    def _is_exempted(self, method_full_name):
        """Check if method should be exempted from auth checks"""
        # Check for health and metrics
        if method_full_name.startswith("/health") or method_full_name.startswith("/metrics"):
            return True
        
        # Check for admin paths
        for path in EXEMPTED_PATHS:
            if path == "/admin/*":
                if "/admin/" in method_full_name:
                    return True
            elif method_full_name.startswith(path):
                return True
        return False

    def _is_admin_method(self, method_full_name):
        """Check if method is an admin method that bypasses auth"""
        return method_full_name in ALLOWED_ADMIN_METHODS

